// Extra Hematology quiz questions — transcribed from an external 148-question
// USMLE-style "Hematology and Malignant Treatment" question bank, routed into
// the matching HEMATOLOGY_TOPICS (see 17-hematology.js), mirroring the
// EXTRA_CARDIO_QUIZ / EXTRA_RHEUM_QUIZ / EXTRA_NEPHRO_QUIZ / EXTRA_ID_QUIZ pattern.
const EXTRA_HEMATOLOGY_QUIZ = {
  "heme-cancer-therapeutics": [
    {q:"A 54-year-old man with newly diagnosed diffuse large B-cell lymphoma is offered rituximab in addition to CHOP chemotherapy. The resident asks why a monoclonal antibody is added to cytotoxic chemotherapy rather than used alone. Which mechanism best explains the added benefit of rituximab?", options:["Direct inhibition of bacterial folate synthesis","Recruitment of immune effector mechanisms such as ADCC and complement-mediated killing after binding a tumor antigen","Irreversible blockade of the BCR-ABL ATP binding pocket","Selective inhibition of the proteasome in plasma cells only","Restoration of normal tumor suppressor p53 transcription"], answer:1, explain:"Monoclonal antibodies bind tumor-associated surface antigens and can trigger antibody-dependent cellular cytotoxicity, complement-mediated lysis, and apoptosis. They are commonly combined with chemotherapy because antibody monotherapy is often insufficient for bulky aggressive tumors."},
    {q:"A patient with Hodgkin lymphoma receives a drug composed of an anti-CD30 antibody linked to a cytotoxic payload. The drug-antigen complex is internalized, traffics to lysosomes, and releases the payload inside the malignant cell. Which therapeutic class is described?", options:["Immune checkpoint inhibitor","Antibody-drug conjugate","Proteasome inhibitor","Bispecific T-cell engager","Alkylating agent"], answer:1, explain:"Antibody-drug conjugates use an antibody to deliver a toxic payload into cells expressing a target antigen. Brentuximab vedotin is the classic anti-CD30 example in Hodgkin lymphoma and some T-cell lymphomas."},
    {q:"A 63-year-old patient with relapsed B-cell lymphoma receives a therapy that binds CD20 on the lymphoma cell and CD3 on cytotoxic T cells, physically bringing the T cell to the malignant B cell. What is the main therapeutic principle?", options:["Blockade of PD-1/PD-L1 signaling","Induction of DNA cross-linking independent of cell cycle phase","Redirecting T cells to tumor cells using a bispecific antibody","Inhibition of tyrosine phosphorylation by BCR-ABL","Depletion of plasma cells through anti-CD38"], answer:2, explain:"Bispecific antibodies link a tumor antigen, such as CD20, to CD3 on T cells. This brings cytotoxic T cells into close contact with malignant cells and promotes killing."},
    {q:"A patient with relapsed Hodgkin lymphoma is treated with nivolumab. Which immune interaction is most directly disrupted by this drug?", options:["CD20 binding to rituximab","PD-1 binding to PD-L1","BCL2 binding to proapoptotic proteins","BTK phosphorylation downstream of the B-cell receptor","CD30 internalization of a cytotoxic payload"], answer:1, explain:"Nivolumab is a PD-1 checkpoint inhibitor. It prevents inhibitory PD-1/PD-L1 signaling, allowing T cells to remain active against tumor cells."},
    {q:"A 48-year-old man with CML begins imatinib. Which molecular event is most directly inhibited?", options:["BCL2-mediated inhibition of apoptosis","Tyrosine kinase activity of BCR-ABL through ATP pocket blockade","Cereblon-dependent degradation of Ikaros and Aiolos","Proteasomal degradation of ubiquitinated proteins","CD20-mediated complement activation"], answer:1, explain:"CML is driven by BCR-ABL, a constitutively active tyrosine kinase. Imatinib binds the ATP pocket and blocks kinase signaling."},
    {q:"A 72-year-old with CLL is treated with ibrutinib. Which signaling pathway is targeted?", options:["B-cell receptor signaling through Bruton's tyrosine kinase","PD-1 signaling on exhausted T cells","PML-RARA-mediated block in promyelocyte differentiation","Tubulin polymerization in mitotic spindle formation","Renal uric acid reabsorption"], answer:0, explain:"Ibrutinib is a BTK inhibitor. BTK is a key cytoplasmic kinase downstream of the B-cell receptor and supports survival of malignant B cells in CLL and some B-cell lymphomas."},
    {q:"An 81-year-old man with newly diagnosed AML is not fit for intensive induction chemotherapy. He receives venetoclax with a hypomethylating agent. What is the primary mechanism of venetoclax?", options:["Inhibition of anti-apoptotic BCL2","Inhibition of DNA gyrase","Direct degradation of CD20","Blockade of calcineurin signaling","Covalent binding of hemoglobin S"], answer:0, explain:"Venetoclax inhibits BCL2, an anti-apoptotic protein overexpressed in CLL and AML. It shifts the balance toward apoptosis and is used with hypomethylating therapy in older or unfit AML patients."},
    {q:"A patient with multiple myeloma is started on bortezomib. Accumulation of misfolded proteins in plasma cells is expected to cause malignant cell death. Which target is inhibited?", options:["Proteasome","Tyrosine kinase BCR-ABL","PD-L1","DNA topoisomerase II only in M phase","Thymidylate synthase"], answer:0, explain:"Bortezomib inhibits the proteasome. Plasma cells are highly dependent on protein processing; blocking proteasomal degradation causes toxic protein accumulation and cell death."},
    {q:"A 59-year-old with multiple myeloma receives lenalidomide. The drug binds cereblon, alters an E3 ubiquitin ligase complex, and promotes degradation of transcription factors important in B cells and plasma cells. Which drug class is this?", options:["IMiD/immunomodulatory drug","Anthracycline","Anti-CD38 monoclonal antibody","Bispecific antibody","Histone deacetylase inhibitor"], answer:0, explain:"Thalidomide and lenalidomide are IMiDs. They bind cereblon and alter substrate targeting of an E3 ligase complex, including degradation of Ikaros/Aiolos."},
    {q:"A 34-year-old with relapsed DLBCL undergoes leukapheresis. His own T cells are genetically engineered ex vivo to express a receptor that binds CD19, expanded, and reinfused. What treatment is being used?", options:["Allogeneic stem cell transplantation","CAR-T-cell therapy","Checkpoint blockade","Autologous stem cell support only","Rituximab maintenance"], answer:1, explain:"CAR-T therapy engineers the patient's T cells to express a chimeric antigen receptor against a tumor antigen such as CD19, followed by expansion and reinfusion."},
    {q:"A patient undergoes an allogeneic hematopoietic stem cell transplant for acute leukemia. Months later, donor T cells recognize residual malignant cells as foreign and reduce relapse risk. Which effect is desired?", options:["Graft-versus-host disease","Graft-versus-leukemia effect","Tumor lysis syndrome","Myelosuppression from conditioning alone","Transfusion-associated graft-versus-host disease"], answer:1, explain:"The graft-versus-leukemia effect is the desired antitumor immune response from donor immune cells. GVHD is the unwanted attack on normal host tissues."},
    {q:"A patient receives high-dose chemotherapy followed by reinfusion of previously collected autologous stem cells. Which statement best describes this strategy?", options:["It primarily works by introducing donor T cells for graft-versus-leukemia activity","It allows delivery of otherwise marrow-toxic chemotherapy doses by rescuing hematopoiesis afterward","It is contraindicated in all lymphomas","It prevents infertility caused by chemotherapy","It is identical to an allogeneic transplant"], answer:1, explain:"High-dose chemotherapy with stem cell support allows administration of marrow-toxic chemotherapy by collecting and reinfusing the patient's stem cells to restore hematopoiesis."},
    {q:"A tumor board recommends combining drugs with different mechanisms and non-overlapping toxicities. Which principle best supports this approach?", options:["All cancer cells in a clonal malignancy are identical and respond identically to one drug","Combination therapy can overcome tumor heterogeneity and reduce emergence of resistant clones","Combination therapy is used only to decrease cost","Cell-cycle-specific drugs cannot be combined with non-cell-cycle-specific drugs","Using more drugs always eliminates toxicity"], answer:1, explain:"Combination chemotherapy targets different tumor subclones and pathways, reduces resistance, and ideally uses drugs with different toxicity profiles."}
  ],
  "heme-chemo-toxicity": [
    {q:"A patient receiving an anthracycline-containing regimen develops a falling ejection fraction on surveillance echocardiography. Which drug class is most likely responsible?", options:["Anthracycline such as doxorubicin or daunorubicin","Bleomycin","Vinblastine","Rituximab","Allopurinol"], answer:0, explain:"Anthracyclines can cause acute or delayed cardiomyopathy and reduced ejection fraction. Echocardiographic monitoring is important, especially when baseline cardiac function is impaired."},
    {q:"A Hodgkin lymphoma patient develops dry cough and reduced DLCO after several cycles of ABVD. Which agent is most associated with this toxicity?", options:["Bleomycin","Dacarbazine","Vinblastine","Doxorubicin","Nivolumab"], answer:0, explain:"Bleomycin is associated with interstitial lung injury and reduced DLCO. PET-adapted Hodgkin therapy often removes bleomycin after a good early response to reduce pulmonary toxicity."},
    {q:"A patient receiving R-CHOP develops stocking-glove numbness and foot drop. Which component is most likely responsible?", options:["Vincristine","Rituximab","Cyclophosphamide","Prednisone","Doxorubicin"], answer:0, explain:"Vincristine commonly causes peripheral neuropathy due to microtubule disruption. Bortezomib can also cause neuropathy in myeloma regimens."},
    {q:"Before starting chemotherapy for newly diagnosed lymphoma, a 27-year-old woman asks about future fertility. What is the most appropriate counseling point?", options:["Fertility preservation should be discussed before therapy, including oocyte, embryo, or ovarian tissue preservation depending on urgency","Chemotherapy never affects fertility in women","Fertility preservation is only relevant after relapse","Only men require fertility counseling before chemotherapy","Pregnancy immediately after induction chemotherapy is recommended"], answer:0, explain:"Cytotoxic chemotherapy can damage rapidly dividing germ cells. Sperm, oocyte, embryo, or gonadal tissue preservation should be discussed before treatment when time allows."},
    {q:"A patient develops chills, fever, and hypotension during the first infusion of a monoclonal antibody. Which prevention strategy is commonly used before subsequent infusions?", options:["Premedication with acetaminophen, antihistamines, and often corticosteroids","High-dose aspirin only","Therapeutic phlebotomy","Rasburicase","Prophylactic cranial irradiation"], answer:0, explain:"Infusion reactions are common with biologic therapies, especially antibodies. Premedication with acetaminophen, antihistamines, and corticosteroids reduces reactions."},
    {q:"A patient who received anthracyclines years ago is asymptomatic but enters survivorship follow-up. Which late toxicity should be monitored?", options:["Delayed cardiomyopathy and coronary disease risk","Immediate APL differentiation syndrome only","Cyclic neutropenia from ELANE","ABO mismatch","Factor XI deficiency"], answer:0, explain:"Anthracycline cardiotoxicity may appear years later, and survivors require cardiac monitoring and risk factor management."},
    {q:"A cancer survivor treated with cytotoxic chemotherapy is monitored for late hematologic complications. Which secondary malignancy is particularly associated with prior cytotoxic therapy?", options:["MDS and AML","CML caused by BCR-ABL from all treatments","MGUS in every patient","Hemophilia A","Sickle cell disease"], answer:0, explain:"Cytotoxic therapies can increase late risk of secondary malignancies, including therapy-related MDS and AML, as well as some solid tumors."},
    {q:"A patient with Hodgkin lymphoma receives bleomycin and later needs oxygen during surgery. Which toxicity history should be communicated to anesthesia?", options:["Bleomycin-associated lung injury risk","Imatinib-associated BCR-ABL monitoring","ATRA differentiation syndrome only","Cereblon binding by IMiDs","Factor XI deficiency"], answer:0, explain:"Prior bleomycin exposure is associated with pulmonary toxicity, and high-concentration oxygen can worsen it; pulmonary function (especially DLCO) is monitored during and after therapy."},
    {q:"A patient with lymphoma develops severe neutropenia after chemotherapy. What prophylactic strategy can reduce neutropenia duration or risk in appropriate regimens?", options:["G-CSF support","Rasburicase after neutrophil recovery only","Therapeutic phlebotomy","Desmopressin","Warfarin"], answer:0, explain:"G-CSF stimulates neutrophil production and can reduce duration/severity of chemotherapy-induced neutropenia in appropriate high-risk regimens."},
    {q:"A patient with ALL is placed on prophylaxis for Pneumocystis jirovecii pneumonia during therapy. Why?", options:["ALL regimens can create significant cellular immune suppression, increasing PCP risk","PCP prophylaxis treats tumor lysis syndrome","PCP prophylaxis prevents anthracycline cardiotoxicity","PCP prophylaxis is a form of anti-CD20 therapy","PCP prophylaxis lowers platelet count"], answer:0, explain:"Some leukemia protocols, including ALL therapy, cause immunosuppression that increases risk for opportunistic infections such as PCP; prophylaxis may be required."},
    {q:"A 70-year-old on chemotherapy has severe nausea and vomiting after each cycle. Which principle is most appropriate?", options:["Use prophylactic antiemetic therapy based on the emetogenicity of the regimen","Wait until severe dehydration occurs before treating nausea","Stop all cancer therapy permanently after any nausea","Treat with phlebotomy","Give cryoprecipitate"], answer:0, explain:"Chemotherapy-induced nausea and vomiting are predictable toxicities. Antiemetic prophylaxis is selected according to regimen emetogenicity and patient risk."}
  ],
  "heme-lymphoma": [
    {q:"A patient receiving bleomycin, doxorubicin, vinblastine, and dacarbazine has a negative interim PET-CT after 2 cycles. Which modification is often used to reduce toxicity while maintaining treatment intensity?", options:["Remove bleomycin and continue AVD","Stop all therapy permanently","Switch immediately to imatinib","Add hydroxyurea","Start lifelong warfarin"], answer:0, explain:"In PET-adapted Hodgkin lymphoma therapy, a negative interim PET after ABVD may allow dropping bleomycin to reduce pulmonary toxicity, continuing AVD."},
    {q:"A Hodgkin lymphoma patient has persistent PET positivity after initial ABVD. What is the rationale for treatment escalation?", options:["Poor early metabolic response suggests higher relapse risk and need for more intensive therapy","A negative PET scan always means refractory disease","Bleomycin toxicity is diagnosed by PET positivity","Checkpoint inhibitors are contraindicated in Hodgkin lymphoma","Radiation never has a role in Hodgkin lymphoma"], answer:0, explain:"Interim PET response in Hodgkin lymphoma helps risk-adapt therapy. Persistent PET avidity after initial therapy suggests inadequate response and may prompt escalation."},
    {q:"A patient with relapsed Hodgkin lymphoma after chemotherapy is referred for high-dose chemotherapy with autologous stem cell support. What is the main purpose of the stem cell infusion?", options:["Provide donor lymphocytes for GVHD","Rescue bone marrow function after high-dose chemotherapy","Neutralize anti-CD20 antibodies","Prevent pulmonary toxicity from bleomycin","Directly lower uric acid"], answer:1, explain:"Autologous stem cell support rescues hematopoiesis after high-dose chemotherapy, allowing more intensive treatment of relapsed disease."},
    {q:"A 60-year-old with newly diagnosed DLBCL has stage III disease. Which regimen is the classic first-line backbone?", options:["R-CHOP","ABVD","ATRA plus ATO","Imatinib alone","Lenalidomide maintenance only"], answer:0, explain:"R-CHOP is a classic first-line regimen for DLBCL. Polatuzumab-based regimens are used in selected settings, and CAR-T/bispecific antibodies are used in relapsed or refractory disease."},
    {q:"A patient with relapsed/refractory DLBCL after standard chemoimmunotherapy is being considered for a therapy that has replaced autologous transplant in many relapsed settings. Which option fits this role?", options:["CAR-T-cell therapy or bispecific antibody therapy","Oral iron alone","Low-dose aspirin alone","Desmopressin","Folic acid replacement only"], answer:0, explain:"Relapsed/refractory DLBCL can be treated with CAR-T cells and bispecific antibodies. These approaches have reduced reliance on autologous transplant in some settings."},
    {q:"A 68-year-old has asymptomatic follicular lymphoma with low tumor burden and no cytopenias. What is the most appropriate initial approach?", options:["Observation until treatment indication develops","Immediate ATRA","Immediate splenectomy","Urgent leukapheresis","ABVD for all patients"], answer:0, explain:"Indolent lymphomas often do not require immediate treatment unless symptomatic, bulky, or causing cytopenias or organ compromise. Follicular lymphoma treatment is often deferred until an indication exists."},
    {q:"A patient has follicular lymphoma with symptomatic disease. Which regimen best matches a common initial treatment strategy?", options:["Bendamustine plus rituximab","ATRA plus ATO","Imatinib plus hydroxyurea","Cefepime plus vancomycin","Cyanocobalamin injections"], answer:0, explain:"Symptomatic follicular lymphoma can be treated with bendamustine plus rituximab. Early relapse within 24 months is a poor prognostic sign."},
    {q:"A 54-year-old man with Hodgkin lymphoma starts ABVD. Which drug in this regimen is an anthracycline?", options:["Doxorubicin/adriamycin","Bleomycin","Vinblastine","Dacarbazine","Rituximab"], answer:0, explain:"ABVD includes doxorubicin (adriamycin), bleomycin, vinblastine, and dacarbazine. Doxorubicin is the anthracycline and is associated with cardiotoxicity."},
    {q:"A DLBCL biopsy shows activated B-cell subtype. The oncologist discusses adding an antibody-drug conjugate targeting CD79b to an R-CHP backbone. Which drug is described?", options:["Polatuzumab vedotin","Brentuximab vedotin","Nivolumab","Imatinib","Venetoclax"], answer:0, explain:"Polatuzumab vedotin is an antibody-drug conjugate targeting CD79b and is used in selected DLBCL regimens, including polatuzumab plus R-CHP."},
    {q:"A Hodgkin lymphoma patient with relapsed disease is offered brentuximab. Which target is most relevant?", options:["CD30","CD20","CD19","BCR-ABL","CD38"], answer:0, explain:"Brentuximab vedotin targets CD30, a key antigen in Hodgkin lymphoma and some T-cell lymphomas."},
    {q:"A patient with relapse of follicular lymphoma within 24 months of therapy has a poorer prognosis. What is this early relapse concept generally implying?", options:["Early progression identifies biologically higher-risk disease","All follicular lymphoma is always curable with observation","It proves MGUS progression","It indicates APL","It is caused by Rh incompatibility"], answer:0, explain:"Early relapse/progression of follicular lymphoma within 24 months is an adverse prognostic marker and suggests higher-risk disease biology."}
  ],
  "heme-mds-aml": [
    {q:"A 41-year-old with newly diagnosed AML is fit for intensive chemotherapy. Cytogenetics show favorable-risk disease. Which induction regimen is most appropriate?", options:["Cytarabine plus an anthracycline, commonly a 7+3 regimen","Ibrutinib monotherapy","R-CHOP","ABVD followed by PET-CT","Bortezomib, lenalidomide, and dexamethasone only"], answer:0, explain:"Fit AML patients usually receive intensive induction with cytarabine plus an anthracycline. Consolidation depends on risk stratification."},
    {q:"A 76-year-old with newly diagnosed AML has severe frailty and cannot tolerate intensive induction. Which regimen best matches the treatment approach in an unfit patient?", options:["High-dose cytarabine plus daunorubicin only","Venetoclax plus a hypomethylating agent","R-CHOP","ABVD","Observation only regardless of symptoms"], answer:1, explain:"Older or unfit AML patients often receive venetoclax plus a hypomethylating agent, rather than intensive 7+3 chemotherapy."},
    {q:"A patient with AML reaches complete remission after induction. Genetic testing shows TP53 mutation and adverse-risk cytogenetics. What consolidation strategy is most likely to offer curative potential?", options:["Allogeneic hematopoietic stem cell transplantation if eligible","No further therapy","Rituximab maintenance only","Low-dose aspirin alone","Oral iron supplementation"], answer:0, explain:"Adverse-risk AML often requires allogeneic transplant in remission if eligible, whereas favorable-risk disease may be consolidated with additional chemotherapy."},
    {q:"A 74-year-old has pancytopenia, macrocytosis, dysplastic neutrophils, and bone marrow showing multilineage dysplasia in more than 10 percent of cells with 8 percent blasts. What diagnosis is most likely?", options:["Myelodysplastic syndrome","AML by blast percentage alone","CLL","Reactive leukocytosis","Iron deficiency anemia"], answer:0, explain:"MDS involves clonal hematopoiesis with dysplasia and cytopenias. AML is generally defined by 20 percent or more blasts or certain defining genetic lesions — this patient's 8% blasts does not meet that threshold."},
    {q:"A low-risk MDS patient has symptomatic anemia, low transfusion needs, and low endogenous EPO. Which therapy is most appropriate?", options:["Erythropoiesis-stimulating agent","Immediate allogeneic transplant for all patients","R-CHOP","ATRA plus ATO","Warfarin"], answer:0, explain:"Low-risk MDS is treated symptomatically, including RBC transfusion support and erythropoiesis-stimulating agents when appropriate. Luspatercept may be used in selected anemia phenotypes."},
    {q:"A high-risk MDS patient has pancytopenia, excess blasts, and adverse cytogenetics. Which strategy can delay progression and which offers full remission potential?", options:["Hypomethylating agent; allogeneic stem cell transplant","Oral iron; splenectomy","Cefepime; vancomycin","Aspirin; phlebotomy","Desmopressin; cryoprecipitate"], answer:0, explain:"High-risk MDS may be treated with hypomethylating agents to delay progression; allogeneic transplant is the main potentially curative strategy in eligible patients."}
  ],
  "heme-all-cll": [
    {q:"A patient with ALL has positive Philadelphia chromosome. Which added therapy is most directly indicated?", options:["Tyrosine kinase inhibitor therapy targeting BCR-ABL","Anti-CD38 antibody alone","Aspirin only","Hydroxyurea lifelong without chemotherapy","Bendamustine plus rituximab only"], answer:0, explain:"Philadelphia chromosome-positive ALL is driven by BCR-ABL and is treated with chemotherapy plus a TKI, with consolidation strategies guided by response and fitness."},
    {q:"A patient with ALL receives systemic chemotherapy. The oncologist adds intrathecal therapy. What is the main reason?", options:["ALL commonly relapses in sanctuary sites such as the CNS where standard chemotherapy may not penetrate adequately","To treat isolated iron deficiency","To prevent bleomycin lung toxicity","To reverse DAT positivity","To lower hematocrit below 45 percent"], answer:0, explain:"ALL has a tendency to involve sanctuary sites, particularly the CNS. CNS-directed prophylaxis or treatment is therefore required."},
    {q:"A 67-year-old is diagnosed with CLL after incidental lymphocytosis. He has no anemia, thrombocytopenia, bulky nodes, B symptoms, or infections. What is the best management?", options:["Observation with monitoring","Immediate multiagent chemotherapy for all patients","Splenectomy","ABVD","Exchange transfusion"], answer:0, explain:"Asymptomatic early-stage CLL is often observed. Treatment is reserved for symptomatic disease, cytopenias, bulky/progressive disease, or high-risk clinical progression."},
    {q:"A patient with known CLL develops rapidly enlarging lymph nodes, fever, weight loss, and rising LDH. Biopsy shows diffuse large B-cell lymphoma. What complication has occurred?", options:["Richter transformation","Tumor lysis syndrome","Warm autoimmune hemolytic anemia only","Felty syndrome","Transient erythroblastopenia"], answer:0, explain:"Richter transformation is transformation of CLL/SLL into an aggressive lymphoma, most often DLBCL, and is suggested by rapidly progressive nodes, B symptoms, and high LDH."},
    {q:"A 72-year-old has persistent lymphocytosis. Smear shows smudge/basket cells. Flow cytometry shows clonal mature B cells. What is the diagnosis?", options:["CLL","ALL","AML","CML","Hairy cell leukemia cannot be inferred"], answer:0, explain:"CLL is a clonal mature B-cell lymphocytosis and classically shows smudge cells on smear."},
    {q:"A 73-year-old with CLL has del(17p)/TP53 mutation. Which statement best describes the implication?", options:["It predicts higher-risk disease and favors targeted therapy such as BTK inhibition or venetoclax-based therapy over traditional chemotherapy","It proves the disease is cured","It mandates ABVD","It excludes the diagnosis of CLL","It means observation is always unsafe even if asymptomatic"], answer:0, explain:"TP53 disruption/del(17p) predicts aggressive CLL and poor chemoimmunotherapy response, favoring targeted agents when treatment is indicated."},
    {q:"A patient with untreated CLL has anemia and thrombocytopenia due to marrow involvement. Which feature marks more advanced disease in Rai/Binet-style staging?", options:["Anemia and thrombocytopenia","No lymph node involvement only","Isolated mild lymphocytosis with no symptoms","Negative flow cytometry","Low ferritin"], answer:0, explain:"Advanced CLL staging includes cytopenias such as anemia and thrombocytopenia, reflecting marrow failure or autoimmune complications."}
  ],
  "heme-mpn": [
    {q:"A 52-year-old with CML has been on imatinib for 12 months. Which test is best for monitoring molecular response?", options:["Quantitative PCR for BCR-ABL","Serum ferritin","Direct antiglobulin test","D-dimer","Factor VIII activity"], answer:0, explain:"CML response is monitored with quantitative PCR for BCR-ABL transcripts. Lack of expected molecular response may prompt dose adjustment or switching TKIs."},
    {q:"A 62-year-old has hematocrit 57 percent, leukocytosis, thrombocytosis, aquagenic pruritus, splenomegaly, low EPO, and JAK2 V617F mutation. What is the treatment target?", options:["Maintain hematocrit below 45 percent with phlebotomy plus low-dose aspirin; add cytoreduction if high risk","Maintain hematocrit above 60 percent","No therapy unless hemoglobin is below 10 g/dL","R-CHOP for all patients","ATRA plus ATO"], answer:0, explain:"Polycythemia vera is treated with phlebotomy to hematocrit below 45 percent plus low-dose aspirin. Older age or thrombosis history often requires hydroxyurea or interferon."},
    {q:"A 70-year-old with essential thrombocythemia has platelets 950,000/uL and prior DVT. Which treatment is most appropriate?", options:["Low-dose aspirin plus hydroxyurea","Observation only","Acyclovir","Iron supplementation only","Cefepime"], answer:0, explain:"High-risk ET includes prior thrombosis and older age. Therapy commonly includes low-dose aspirin and cytoreduction with hydroxyurea."},
    {q:"A patient has thrombocytosis, microcytic hypochromic anemia, low ferritin, and high CRP after chronic blood loss. JAK2 testing is negative. What is the likely cause of thrombocytosis?", options:["Reactive thrombocytosis from iron deficiency/inflammation","Essential thrombocythemia","CML blast crisis","Pseudothrombocytopenia","Acute promyelocytic leukemia"], answer:0, explain:"Reactive thrombocytosis is common with iron deficiency, infection, inflammation, trauma, smoking, and post-splenectomy states. Treating the cause often corrects the platelet count."},
    {q:"A 66-year-old has massive splenomegaly, constitutional symptoms, anemia, teardrop cells, and bone marrow fibrosis with reticulin. Which disease is most likely?", options:["Primary myelofibrosis","Iron deficiency anemia","Acute ITP","vWD type I","Factor XI deficiency"], answer:0, explain:"Primary myelofibrosis causes marrow fibrosis, extramedullary hematopoiesis, splenomegaly, cytopenias, and teardrop cells. Symptomatic therapy may include JAK inhibitors; transplant is considered in high-risk patients."},
    {q:"A 55-year-old has erythrocytosis with elevated EPO, chronic hypoxemia, and severe COPD. Which category best fits his polycythemia?", options:["Secondary appropriate erythrocytosis","Polycythemia vera","Relative polycythemia only","Essential thrombocythemia","Acute leukemia"], answer:0, explain:"Chronic hypoxemia appropriately raises EPO and causes secondary erythrocytosis. PV typically has low EPO and a JAK2 mutation instead."},
    {q:"A patient with erythrocytosis has normal oxygen saturation, normal EPO, and suspected high-affinity hemoglobin. Which test can support this diagnosis?", options:["Venous P50 measurement","Direct Coombs test","Serum tryptase","Urine anion gap","Factor VIII inhibitor assay"], answer:0, explain:"High-affinity hemoglobin variants cause erythrocytosis with impaired oxygen delivery. Venous P50 helps diagnose altered hemoglobin oxygen affinity."},
    {q:"A 50-year-old with CML has excellent molecular response for years. His physician discusses a state where disease remains detectable by sensitive methods but does not affect survival or day-to-day health. Which term best describes this concept?", options:["Functional cure","Tumor lysis syndrome","Complete ABO mismatch","Leukemoid reaction","DIC"], answer:0, explain:"A functional cure in CML means disease may be molecularly detectable but is clinically controlled and not expected to shorten life if response is maintained."}
  ],
  "heme-emergencies": [
    {q:"A 36-year-old with suspected acute promyelocytic leukemia presents with gingival bleeding, low fibrinogen, prolonged PT/PTT, and circulating abnormal promyelocytes. What is the most appropriate immediate therapy?", options:["Start ATRA immediately while confirmatory testing is pending","Delay therapy until t(15;17) is confirmed","Start imatinib","Perform splenectomy","Give rituximab only"], answer:0, explain:"APL is a hematologic emergency due to DIC risk. ATRA should be started immediately when APL is suspected, with aggressive blood product support."},
    {q:"A patient with APL develops new dyspnea, pulmonary infiltrates, edema, and rising creatinine several days after starting ATRA. What is the most likely diagnosis?", options:["Differentiation syndrome","ABO-incompatible transfusion reaction","Chronic GVHD","Sideroblastic anemia","May-Thurner syndrome"], answer:0, explain:"ATRA/ATO therapy can trigger differentiation syndrome due to cytokine release and capillary leak. High-dose corticosteroids are used and ATRA may be held in severe cases."},
    {q:"A patient with Burkitt lymphoma begins chemotherapy. Twelve hours later he has K 6.6 mEq/L, phosphate 6.0 mg/dL, uric acid 12 mg/dL, calcium 6.9 mg/dL, and rising creatinine. What is the diagnosis?", options:["Tumor lysis syndrome","Differentiation syndrome","DIC only","Autoimmune hemolytic anemia","TACO"], answer:0, explain:"Tumor lysis syndrome causes hyperkalemia, hyperphosphatemia, hyperuricemia, hypocalcemia, and AKI after rapid lysis of malignant cells."},
    {q:"A patient at very high risk for tumor lysis syndrome needs rapid uric acid reduction. Which drug is most effective but contraindicated in G6PD deficiency?", options:["Rasburicase","Allopurinol","Hydroxyurea","Cefepime","Idarucizumab"], answer:0, explain:"Rasburicase directly degrades uric acid and rapidly lowers levels, but can cause hemolysis/methemoglobinemia in G6PD deficiency."},
    {q:"A 45-year-old with AML has WBC 180,000/uL, severe dyspnea, hypoxemia, headache, and visual changes. Chest imaging shows diffuse infiltrates. What complication is most likely?", options:["Leukostasis from hyperleukocytosis","Iron deficiency anemia","Essential thrombocythemia","TRALI","Factor XI deficiency"], answer:0, explain:"Hyperleukocytosis, especially in AML/ALL, can cause leukostasis with pulmonary and neurologic symptoms from microvascular obstruction."},
    {q:"In a patient with symptomatic hyperleukocytosis from AML, which supportive transfusion principle is most appropriate?", options:["Avoid unnecessary RBC transfusion unless hemoglobin is very low or symptoms are severe, because it may worsen viscosity","Transfuse RBCs to hemoglobin 15 g/dL immediately","Give platelets only if the count is above 1,000,000/uL","Never hydrate patients with leukostasis","Use washed RBCs to treat leukostasis directly"], answer:0, explain:"In leukostasis, blood viscosity is already high. RBC transfusion is reserved for clear indications such as hemoglobin below about 7 g/dL or severe symptoms, while cytoreduction and hydration are prioritized."},
    {q:"A patient receiving induction chemotherapy for ALL has ANC 0/uL and temperature 38.6 C. He is hemodynamically stable and has no catheter infection. Which empiric therapy is appropriate?", options:["Cefepime or piperacillin-tazobactam started promptly","Ceftriaxone monotherapy","Oral amoxicillin only","No antibiotics until cultures are positive","Acyclovir only"], answer:0, explain:"Febrile neutropenia is a medical emergency. Empiric therapy must cover Pseudomonas, with agents such as cefepime, piperacillin-tazobactam, or meropenem."},
    {q:"A neutropenic patient remains febrile after 5 days of broad-spectrum antibacterial therapy, and CT chest shows nodular infiltrates with a halo sign. What should be added?", options:["Broad-spectrum antifungal therapy such as voriconazole or an echinocandin depending on suspected pathogen","Oral iron","Desmopressin","Aspirin only","Phlebotomy"], answer:0, explain:"Persistent fever in high-risk neutropenia after several days of antibacterial therapy requires evaluation for invasive fungal infection and addition of empiric or preemptive antifungal therapy."},
    {q:"A patient with profound neutropenia develops black necrotic skin lesions with erythematous halos and later has blood cultures positive for Pseudomonas aeruginosa. Which skin finding is described?", options:["Ecthyma gangrenosum","Erythema nodosum","Livedo reticularis","Koilonychia","Pastia lines"], answer:0, explain:"Ecthyma gangrenosum is classically associated with Pseudomonas bacteremia, especially in neutropenic patients."},
    {q:"A lymphoma patient develops progressive back pain, bilateral leg weakness, and urinary retention. What is the most appropriate next diagnostic test?", options:["Urgent MRI of the entire spine","Peripheral blood smear only","D-dimer","Serum ferritin","Skin prick testing"], answer:0, explain:"Progressive neurologic deficits with back pain in malignancy suggest spinal cord compression. MRI of the entire spine is the key diagnostic test."},
    {q:"A patient with lymphoma develops facial swelling, distended neck veins, orthopnea, and upper extremity edema. Imaging shows mediastinal mass compression of a major vein. What syndrome is present?", options:["Superior vena cava syndrome","Tumor lysis syndrome","TTP","Nephrotic syndrome","TACO"], answer:0, explain:"SVC syndrome causes facial/neck swelling, JVP, orthopnea, and upper extremity edema due to obstruction of venous return from the upper body."},
    {q:"A chemotherapy regimen has a high risk of tumor lysis syndrome. Which prophylaxis is most appropriate before treatment starts?", options:["Aggressive hydration without potassium plus uric acid-lowering therapy such as allopurinol or rasburicase in high-risk patients","Fluid restriction and calcium supplementation for all patients","Warfarin and aspirin","No laboratory monitoring","Only oral iron"], answer:0, explain:"TLS prophylaxis includes aggressive hydration, avoidance of potassium-containing fluids, close electrolyte monitoring, and uric acid-lowering therapy. Rasburicase is used for high-risk patients unless contraindicated."},
    {q:"A patient with APL has platelets 18,000/uL and fibrinogen 80 mg/dL. In addition to ATRA, what supportive treatment goal is important?", options:["Aggressive platelet and cryoprecipitate support to reduce catastrophic bleeding risk","Avoid all transfusions regardless of bleeding","Only warfarin","Phlebotomy to hematocrit below 45 percent","Leukoreduction with no coagulation support"], answer:0, explain:"APL is highly associated with DIC and life-threatening bleeding. Platelet and fibrinogen support with cryoprecipitate is crucial while differentiation therapy starts."},
    {q:"A 46-year-old with AML has WBC 120,000/uL and fever. What empiric antibiotic principle applies if neutropenic fever criteria are met or expected?", options:["Start broad antipseudomonal antibiotics promptly, such as cefepime, piperacillin-tazobactam, or meropenem","Use ceftriaxone alone as standard initial therapy","Wait for ANC recovery before treating","Only treat if sputum culture is positive","Use oral azithromycin only"], answer:0, explain:"Febrile neutropenia or expected profound neutropenia requires immediate antipseudomonal broad-spectrum therapy. Ceftriaxone alone is inadequate for initial high-risk neutropenic fever."},
    {q:"A patient with neutropenic fever has hemodynamic instability and erythema around a central venous catheter. What addition to initial antipseudomonal therapy is most appropriate?", options:["Vancomycin","Oral iron","Aspirin only","Desmopressin","Allopurinol only"], answer:0, explain:"Vancomycin is added in neutropenic fever when there is hemodynamic instability, catheter-related infection, known MRSA colonization/infection, severe skin/soft tissue infection, or certain pneumonia scenarios."}
  ],
  "heme-mm": [
    {q:"A 69-year-old presents with anemia, creatinine 2.4 mg/dL, calcium 12.1 mg/dL, low albumin, and total protein 10.5 g/dL. SPEP shows an M spike. Which disease-defining framework supports active myeloma?", options:["SLiM-CRAB criteria","Duke criteria","Wells score","CURB-65","H2FPEF"], answer:0, explain:"Active multiple myeloma is defined by SLiM-CRAB features: high marrow plasma cell burden, abnormal free light chain ratio, MRI lesions, hypercalcemia, renal dysfunction, anemia, or bone lesions."},
    {q:"A patient has 8 percent clonal plasma cells in bone marrow, M-protein 1.2 g/dL, no anemia, renal dysfunction, hypercalcemia, or bone lesions. What is the most likely diagnosis?", options:["MGUS","Smoldering multiple myeloma","Active multiple myeloma","Waldenstrom macroglobulinemia with hyperviscosity","AL amyloidosis with nephrotic syndrome"], answer:0, explain:"MGUS has less than 10 percent marrow plasma cells, M-protein less than 3 g/dL, and no myeloma-defining end-organ damage."},
    {q:"A patient with multiple myeloma has painful focal lytic lesions and a paraspinal mass compressing the spinal cord. Which statement about radiation is most accurate?", options:["Radiation is not used to cure diffuse marrow disease but can palliate focal painful bone masses or cord compression","Radiation replaces all systemic myeloma therapy","Radiation is contraindicated in all plasma cell tumors","Radiation prevents tumor lysis syndrome","Radiation reverses anti-CD38 resistance"], answer:0, explain:"Myeloma is systemic and marrow-based, so radiation is generally focal and palliative, especially for painful bone lesions or masses causing spinal cord compression."},
    {q:"A newly diagnosed myeloma patient is started on induction therapy with a proteasome inhibitor, an immunomodulator, steroids, and an anti-CD38 antibody. What additional supportive measure directly targets skeletal complications?", options:["Bisphosphonate therapy","ATRA","Imatinib","Therapeutic phlebotomy","Desmopressin"], answer:0, explain:"Bisphosphonates reduce skeletal-related events in myeloma by shifting bone balance away from osteoclast-mediated destruction."},
    {q:"A multiple myeloma patient presents with confusion, constipation, calcium 14 mg/dL, and creatinine 2.1 mg/dL. Which acute therapy combination is most appropriate?", options:["IV hydration, calcitonin for rapid short-term effect, and bisphosphonate therapy","ATRA and ATO","Rituximab and CHOP","Warfarin and aspirin only","Iron and vitamin C"], answer:0, explain:"Myeloma-associated hypercalcemia is treated with IV fluids, calcitonin for rapid temporary lowering, and bisphosphonates for longer effect. Loop diuretics are used only if volume overloaded."},
    {q:"A 61-year-old has symptomatic myeloma and is eligible for transplant. Which treatment sequence best matches standard strategy?", options:["Induction with combination therapy followed by autologous stem cell transplant/consolidation and maintenance","Radiation to the entire skeleton as curative monotherapy","Observation only because myeloma is always asymptomatic","ATRA plus ATO","R-CHOP followed by no follow-up"], answer:0, explain:"Eligible myeloma patients receive combination induction, stem cell collection/autologous transplant or consolidation, and maintenance. Supportive care is integral."},
    {q:"A patient with myeloma is advised to avoid NSAIDs and iodinated contrast when possible. What complication is being prevented?", options:["Worsening kidney dysfunction","Bleomycin lung toxicity","Rituximab infusion reaction","Antiphospholipid syndrome","Hemophilia A"], answer:0, explain:"Myeloma commonly affects kidneys through light chains, hypercalcemia, dehydration, and nephrotoxins. Avoiding nephrotoxic drugs and maintaining hydration are key."},
    {q:"A patient with myeloma on IMiD-based therapy is prescribed aspirin. What is the main reason?", options:["Increased thrombosis risk in myeloma and some myeloma regimens","Treatment of BCR-ABL fusion","Prevention of bleomycin lung toxicity","Reversal of dabigatran","Correction of B12 deficiency"], answer:0, explain:"Myeloma and IMiD-containing regimens increase thrombotic risk. Aspirin or stronger anticoagulation may be used depending on risk."},
    {q:"A patient with a monoclonal gammopathy has 35 percent clonal plasma cells in marrow but no CRAB features and no SLiM biomarkers. What category is most appropriate?", options:["Smoldering multiple myeloma","MGUS","Active multiple myeloma","DLBCL","CML"], answer:0, explain:"Smoldering myeloma has 10-59 percent clonal plasma cells and lacks myeloma-defining events. Active myeloma is defined by SLiM-CRAB criteria."},
    {q:"A patient with myeloma receives daratumumab. Which target is most directly recognized?", options:["CD38 on plasma cells","CD20 on mature B cells","CD30 on Hodgkin Reed-Sternberg cells","BCR-ABL in CML","PD-1 on T cells"], answer:0, explain:"Daratumumab is an anti-CD38 monoclonal antibody used in multiple myeloma combination regimens."}
  ],
  "heme-anemia-micro": [
    {q:"A 38-year-old woman has fatigue, pica, brittle nails, Hb 8.6 g/dL, MCV 68 fL, high RDW, low ferritin, and thrombocytosis. Which smear finding is most expected?", options:["Microcytic hypochromic RBCs with anisopoikilocytosis and pencil cells","Macro-ovalocytes with hypersegmented neutrophils","Target cells with normal RDW and high RBC count","Schistocytes only","Spherocytes with positive direct Coombs"], answer:0, explain:"Iron deficiency anemia causes microcytosis, hypochromia, high RDW, pencil/cigar cells, and often reactive thrombocytosis."},
    {q:"A 25-year-old man has MCV 62 fL, hemoglobin 12.5 g/dL, RBC count increased, RDW normal, and mild splenomegaly. Iron studies are normal. Which diagnostic test is most appropriate?", options:["Hemoglobin electrophoresis","Direct antiglobulin test","Bone marrow biopsy for MDS","Serum tryptase","D-dimer"], answer:0, explain:"Very low MCV with normal RDW and high RBC count suggests beta-thalassemia trait. Hemoglobin electrophoresis evaluates HbA2/HbF changes."},
    {q:"A man with iron deficiency anemia has a ferritin of 90 ng/mL during active pneumonia. Which statement is most accurate?", options:["Ferritin can be falsely normal or high because it is an acute-phase reactant","Ferritin always rules out iron deficiency if above 40 ng/mL","TIBC is never useful in iron deficiency","Iron deficiency always causes low RDW","Iron studies should be interpreted without clinical context"], answer:0, explain:"Ferritin rises with inflammation and can mask iron deficiency. Iron studies must be interpreted in clinical context."},
    {q:"A patient with iron deficiency starts oral iron. Which instruction is most appropriate?", options:["Take iron before meals with water or orange juice if tolerated, and continue therapy for months until iron stores recover","Stop as soon as hemoglobin rises by 0.5 g/dL","Take iron only with calcium supplements","Use phlebotomy weekly","Avoid evaluation for bleeding in adult men"], answer:0, explain:"Oral iron is usually continued for at least 3 months and until iron stores recover. It is best absorbed on an empty stomach with vitamin C, though GI effects may limit adherence."},
    {q:"A patient has microcytic anemia after gastric bypass surgery. Which mechanism best explains reduced iron absorption?", options:["Bypassed or impaired upper intestinal absorption and reduced gastric acid environment","Increased erythropoietin production","Anti-factor VIII inhibitor","ADAMTS13 deficiency","PD-1/PD-L1 activation"], answer:0, explain:"Iron deficiency can occur after bariatric surgery due to impaired absorption and altered gastric/duodenal physiology."},
    {q:"A patient with beta-thalassemia major requires regular transfusions. Which supportive issue becomes especially important over time?", options:["Iron overload management and folic acid support","Avoidance of all blood products forever","Immediate ATRA for all patients","Warfarin for all children","Checkpoint inhibitor maintenance"], answer:0, explain:"Beta-thalassemia major requires chronic transfusions, which can cause iron overload; supportive management includes transfusions, iron chelation/monitoring, and folate."}
  ],
  "heme-anemia-megalo-hemolytic": [
    {q:"A vegan patient has macrocytic anemia, paresthesias, impaired vibration sense, and confusion. Which metabolite pattern is most consistent with the diagnosis?", options:["Elevated methylmalonic acid and elevated homocysteine","Normal methylmalonic acid and elevated homocysteine only","Low ferritin and high TIBC","Low LDH and low indirect bilirubin","Low uric acid and low potassium"], answer:0, explain:"B12 deficiency causes neurologic dysfunction and raises both methylmalonic acid and homocysteine. Folate deficiency raises homocysteine but not methylmalonic acid."},
    {q:"A pregnant patient with poor dietary intake has macrocytosis, glossitis, hypersegmented neutrophils, low folate, normal methylmalonic acid, and elevated homocysteine. Which treatment is most appropriate?", options:["Oral folic acid replacement","Monthly phlebotomy","ATRA","Rituximab","Eculizumab"], answer:0, explain:"Folate deficiency causes megaloblastic anemia without neurologic findings and is treated with folic acid. B12 deficiency must be excluded before folate-only treatment if neurologic features exist."},
    {q:"A patient with pernicious anemia starts IM cyanocobalamin. Which early laboratory response is expected?", options:["Reticulocytosis within several days, followed by hemoglobin rise around 1-2 weeks","Immediate normalization of ferritin within 24 hours","Severe thrombocytosis is diagnostic of treatment failure","No marrow response for 6 months","Immediate fall in methylmalonic acid with worsening neurologic disease"], answer:0, explain:"B12 replacement causes reticulocytosis within days and hemoglobin rise after about 10 days. Transient hypokalemia can occur due to brisk hematopoiesis."},
    {q:"A 68-year-old with rheumatoid arthritis has normocytic anemia, low serum iron, low TIBC, and high ferritin. Which mediator explains the iron pattern?", options:["Hepcidin-mediated trapping of iron in macrophages and reduced intestinal absorption","Loss of intrinsic factor from parietal cell antibodies","ADAMTS13 deficiency","JAK2 V617F mutation","Factor VIII inhibitor"], answer:0, explain:"Anemia of chronic inflammation is driven by cytokine-induced hepcidin, which reduces iron release from macrophages and decreases intestinal absorption."},
    {q:"A patient with CLL develops jaundice, elevated LDH, low haptoglobin, spherocytes, and a positive direct antiglobulin test for IgG without complement. Which diagnosis is most likely?", options:["Warm autoimmune hemolytic anemia","Cold agglutinin disease","G6PD deficiency","Beta-thalassemia minor","Iron deficiency anemia"], answer:0, explain:"Warm AIHA is usually IgG-mediated, causes extravascular hemolysis with spherocytes, and is associated with CLL, lymphoma, SLE, and drugs."},
    {q:"After Mycoplasma pneumonia, a patient develops acrocyanosis and hemolysis. Direct antiglobulin test is positive for C3, and RBC agglutination is seen at low temperature. What is the mechanism?", options:["IgM-mediated cold autoimmune hemolysis with complement fixation","IgG-mediated warm hemolysis without complement","Decreased beta-globin synthesis","Iron malabsorption from celiac disease","Inherited spectrin deficiency only"], answer:0, explain:"Cold AIHA is usually IgM-mediated and complement-positive, often triggered by infections such as Mycoplasma or EBV."},
    {q:"A patient with anemia has high reticulocytes, high indirect bilirubin, high LDH, and low haptoglobin. Direct Coombs test is negative, and smear shows schistocytes. Which broad category is most likely?", options:["Nonimmune microangiopathic hemolytic anemia","Pernicious anemia","Iron deficiency from menstrual blood loss","Anemia of chronic disease","Pure red cell aplasia"], answer:0, explain:"Schistocytes with Coombs-negative hemolysis suggest nonimmune mechanical hemolysis such as TTP, HUS, DIC, malignant hypertension, or prosthetic valves."},
    {q:"A 22-year-old with lifelong jaundice, splenomegaly, and anemia has spherocytes on smear and a negative direct Coombs test. His father had splenectomy. What is the most likely diagnosis?", options:["Hereditary spherocytosis","Warm AIHA","Cold AIHA","Acquired hemophilia A","Essential thrombocythemia"], answer:0, explain:"Hereditary spherocytosis is a membrane cytoskeletal disorder, often due to spectrin-related defects, causing extravascular hemolysis and spherocytes with negative DAT."},
    {q:"A 70-year-old with fatigue has Hb 9.5 g/dL, MCV 106 fL, platelets 105,000/uL, WBC 2,800/uL, and neutrophils with hypersegmentation. Which deficiency should be considered before giving folate alone?", options:["Vitamin B12 deficiency","Factor XI deficiency","JAK2 mutation","BCR-ABL fusion","Protein C deficiency"], answer:0, explain:"B12 deficiency can cause neurologic injury and megaloblastic pancytopenia. Folate can improve anemia while neurologic injury continues, so B12 should be assessed/repleted when uncertain."}
  ],
  "heme-thrombocytopenia": [
    {q:"A 6-year-old develops petechiae two weeks after a viral illness. Platelets are 14,000/uL, hemoglobin and WBC are normal, PT/PTT are normal, smear shows large platelets, and Coombs test is negative. What is the most likely diagnosis?", options:["Acute immune thrombocytopenia","DIC","Aplastic anemia","TTP","Acute leukemia"], answer:0, explain:"ITP is a diagnosis of exclusion with isolated thrombocytopenia, normal coagulation tests, large platelets, and no other smear abnormalities. Acute ITP in children is often postviral and self-limited."},
    {q:"A 45-year-old with chronic ITP has platelets 8,000/uL and epistaxis. Which initial treatment is appropriate?", options:["Corticosteroids with IVIG if rapid platelet rise is needed","No therapy because all ITP is self-limited","Warfarin","Phlebotomy","Imatinib"], answer:0, explain:"Symptomatic ITP or platelets below about 20,000/uL generally requires treatment. Corticosteroids are first-line; IVIG is useful when rapid increase is needed."},
    {q:"A patient has platelet count 28,000/uL by automated analyzer, but smear shows platelet clumping in an EDTA tube and no bleeding history. What is the best next step?", options:["Repeat count using a different anticoagulant and review smear","Start steroids for ITP immediately","Perform splenectomy","Give ATRA","Start warfarin"], answer:0, explain:"EDTA-dependent pseudothrombocytopenia causes falsely low automated platelet counts from clumping. Repeat testing with another anticoagulant and smear review confirms it."},
    {q:"A pregnant patient has platelets 92,000/uL in the third trimester, no hypertension, no hemolysis, and no bleeding. Which diagnosis is most likely?", options:["Gestational thrombocytopenia","TTP","DIC","APL","Essential thrombocythemia"], answer:0, explain:"Mild thrombocytopenia around 80,000-100,000/uL can occur normally in pregnancy. Absence of hemolysis, hypertension, liver injury, or bleeding supports gestational thrombocytopenia."},
    {q:"A patient has thrombocytopenia, neurologic symptoms, renal injury, fever, and MAHA with schistocytes. Which enzyme deficiency classically causes TTP?", options:["ADAMTS13 deficiency","Pyruvate kinase deficiency","G6PD deficiency","C1 esterase inhibitor deficiency","Intrinsic factor deficiency"], answer:0, explain:"TTP is caused by severe ADAMTS13 deficiency, leading to accumulation of ultra-large vWF multimers and platelet-rich microthrombi."}
  ],
  "heme-leukopenia-leukocytosis": [
    {q:"A patient with long-standing RA develops neutropenia and splenomegaly. Which syndrome should be considered?", options:["Felty syndrome","May-Thurner syndrome","Richter transformation","DIC","HDFN"], answer:0, explain:"Felty syndrome is the triad of rheumatoid arthritis, splenomegaly, and neutropenia. T-LGL leukemia can mimic it."},
    {q:"A child has recurrent oral ulcers and fevers every 21 days, with severe neutropenia during episodes and normal counts between episodes. Which mutation is classically implicated?", options:["ELANE","JAK2","BCR-ABL","PML-RARA","BCL2"], answer:0, explain:"Cyclic neutropenia occurs in periodic cycles and is associated with ELANE mutations. Severe congenital neutropenia can also involve ELANE or HAX1 and carries AML risk."},
    {q:"A CBC shows WBC 65,000/uL after severe pneumonia. Smear shows mature neutrophils with left shift, and leukocyte alkaline phosphatase is high. No basophilia or BCR-ABL fusion is found. What is the best interpretation?", options:["Leukemoid reaction","CML","AML","CLL","T-LGL leukemia"], answer:0, explain:"A leukemoid reaction is reactive leukocytosis, often above 50,000/uL, due to infection or stress. CML is associated with BCR-ABL and often basophilia."},
    {q:"A patient with breast cancer develops anemia and thrombocytopenia. Smear shows nucleated RBCs and early myeloid precursors. What process is suggested?", options:["Bone marrow infiltration causing a leukoerythroblastic picture","Simple iron deficiency only","Benign ethnic neutropenia","vWD type I","Gestational thrombocytopenia"], answer:0, explain:"A leukoerythroblastic smear with nucleated RBCs and myeloid precursors suggests marrow infiltration, myelofibrosis, or severe marrow stress."},
    {q:"A patient has severe congenital neutropenia due to HAX1 mutation. Which long-term complication is especially important?", options:["Increased AML risk","Guaranteed cure without monitoring","High factor VIII level causing hemophilia","Isolated hypercalcemia from myeloma","Essential thrombocythemia in infancy"], answer:0, explain:"Severe congenital neutropenia can be associated with recurrent infections and increased AML/MDS risk. G-CSF is used to improve neutrophil counts."},
    {q:"A patient has eosinophilia on CBC. Which value best defines eosinophilia?", options:["Absolute eosinophil count greater than 450/uL","Platelets greater than 450,000/uL","Hemoglobin greater than 16.5 g/dL","ANC less than 500/uL","MCV greater than 100 fL"], answer:0, explain:"Eosinophilia is defined as an absolute eosinophil count greater than 450/uL. Interpretation requires clinical context, including allergy, parasites, drugs, malignancy, and autoimmune disease."}
  ],
  "heme-lymphadenopathy-splenomegaly": [
    {q:"An adult has a firm, nontender left supraclavicular lymph node and weight loss. What is the most appropriate next step?", options:["Biopsy of the lymph node before empiric therapy","Immediate antibiotics for all supraclavicular nodes","Reassurance only","Phlebotomy","Desmopressin"], answer:0, explain:"Supraclavicular lymphadenopathy is concerning for malignancy such as lung or gastric cancer. Tissue diagnosis should be obtained before therapy when feasible."},
    {q:"A patient undergoes splenectomy for hereditary spherocytosis. Which long-term risk and prevention strategy are most important?", options:["Overwhelming infection with encapsulated bacteria; vaccination and prompt broad antibiotics for fever","CML; imatinib prophylaxis","Iron deficiency; routine phlebotomy","Allergic rhinitis; antihistamines","Tumor lysis syndrome; rasburicase before every infection"], answer:0, explain:"Asplenic patients have high risk of overwhelming post-splenectomy infection, especially from encapsulated organisms. Vaccination and urgent evaluation/antibiotics for fever are essential."},
    {q:"A peripheral smear after splenectomy shows small nuclear remnants in RBCs. What are these inclusions?", options:["Howell-Jolly bodies","Auer rods","Dohle bodies","Heinz bodies","Schistocytes"], answer:0, explain:"Howell-Jolly bodies are nuclear DNA remnants normally cleared by the spleen; they are seen after splenectomy or functional asplenia."}
  ],
  "heme-hemostasis-bleeding": [
    {q:"A patient has lifelong hemarthroses and deep muscle bleeding. Platelet count is normal, PT is normal, and aPTT is prolonged. Which category is most likely?", options:["Coagulation factor deficiency such as hemophilia A or B","Platelet adhesion disorder only","Iron deficiency","Polycythemia vera","ITP"], answer:0, explain:"Deep tissue bleeding and hemarthroses suggest a coagulation factor deficiency. Hemophilia A/B causes isolated prolonged aPTT."},
    {q:"A teenager has epistaxis, menorrhagia, easy bruising, normal platelet count, and mildly prolonged aPTT. Family history is positive in both sexes. Which diagnosis is most likely?", options:["von Willebrand disease","Hemophilia A","Factor XI deficiency only","DIC","TTP"], answer:0, explain:"vWD causes mucocutaneous bleeding, can prolong aPTT due to reduced factor VIII stabilization, and is often inherited in an autosomal dominant pattern."},
    {q:"A patient with vWD type 1 is scheduled for a dental procedure. Which therapy can increase endogenous vWF release in many patients?", options:["Desmopressin","Imatinib","Rasburicase","Allopurinol","Cefepime"], answer:0, explain:"Desmopressin can increase release of vWF and factor VIII in many patients with type 1 vWD. Cryoprecipitate or vWF concentrates may be needed in selected cases."},
    {q:"A 40-year-old Ashkenazi Jewish patient has excessive bleeding after tonsillectomy but no spontaneous hemarthroses. PT is normal and aPTT is mildly prolonged. Which deficiency is most likely?", options:["Factor XI deficiency","Factor VII deficiency","Protein C deficiency","ADAMTS13 deficiency","JAK2 mutation"], answer:0, explain:"Factor XI deficiency is more common in Ashkenazi Jews and often presents with surgical bleeding rather than spontaneous bleeding."},
    {q:"A postpartum patient has severe soft tissue bleeding and isolated prolonged aPTT. Mixing study initially corrects but becomes prolonged after incubation. Which diagnosis is most likely?", options:["Acquired hemophilia A due to factor VIII inhibitor","Congenital factor XI deficiency","Iron deficiency anemia","Platelet storage pool disease","Polycythemia vera"], answer:0, explain:"Acquired hemophilia A is caused by an inhibitor to factor VIII. Incubated mixing studies may reveal time-dependent inhibitor activity."},
    {q:"A septic patient has oozing from IV sites, thrombocytopenia, prolonged PT and aPTT, elevated D-dimer, low fibrinogen, and schistocytes. Which process is present?", options:["DIC","vWD type I","Hemophilia B","Factor XII deficiency","Essential thrombocythemia"], answer:0, explain:"DIC causes systemic activation of coagulation and fibrinolysis, with bleeding and thrombosis, low fibrinogen, high D-dimer, prolonged coagulation tests, thrombocytopenia, and schistocytes."},
    {q:"A patient with cirrhosis has prolonged PT and thrombocytopenia but no active bleeding. Which statement is most accurate?", options:["Standard coagulation tests do not fully predict bleeding because procoagulant and anticoagulant factors are both altered","All clotting factors including factor VIII are absent","Platelets are always normal in cirrhosis","D-dimer is never elevated","Warfarin is mandatory for all cirrhotic patients"], answer:0, explain:"Liver disease affects many clotting factors and fibrinolytic/anticoagulant pathways. PT/INR alone does not fully capture bleeding or thrombotic risk."},
    {q:"A patient on dabigatran presents with life-threatening intracranial bleeding. Which reversal agent is most specific?", options:["Idarucizumab","Andexanet alfa","Vitamin K only","Protamine only","Desmopressin"], answer:0, explain:"Idarucizumab specifically reverses dabigatran, a direct thrombin inhibitor."},
    {q:"A patient taking apixaban has severe GI bleeding and hemodynamic instability. Which reversal strategy is most appropriate if available?", options:["Andexanet alfa or PCC when direct antidote is unavailable","Idarucizumab","ATRA","Phlebotomy","Rituximab"], answer:0, explain:"Andexanet alfa reverses factor Xa inhibitors such as apixaban and rivaroxaban. PCC is used when the direct antidote is not available or appropriate."},
    {q:"A patient has mucocutaneous bleeding with normal PT, normal aPTT, and normal platelet count. Which diagnosis remains possible?", options:["von Willebrand disease or platelet function disorder","Hemophilia A is excluded and no bleeding disorder exists","DIC is most likely","Factor VII deficiency is most likely","Polycythemia vera is diagnostic"], answer:0, explain:"Normal PT/aPTT does not exclude vWD, platelet function disorders, factor XIII deficiency, telangiectasias, or dysfibrinogenemia. Mucocutaneous bleeding suggests primary hemostasis problems."},
    {q:"A patient with suspected congenital factor deficiency has prolonged aPTT. Mixing study immediately corrects and remains corrected after incubation. What does this suggest?", options:["Factor deficiency rather than inhibitor","Time-dependent factor VIII inhibitor","Lupus anticoagulant with thrombosis risk only","DIC","EDTA artifact"], answer:0, explain:"Correction with mixing suggests factor deficiency. Failure to correct, especially after incubation, suggests an inhibitor such as acquired hemophilia A."},
    {q:"A patient with bleeding of unknown cause before surgery has a normal initial workup. Which therapy can reduce mucosal bleeding by inhibiting fibrinolysis?", options:["Tranexamic acid/hexakapron","Imatinib","Rasburicase","Bortezomib","Nivolumab"], answer:0, explain:"Antifibrinolytics such as tranexamic acid can be used perioperatively or for mucosal bleeding in selected bleeding disorders."},
    {q:"Which bleeding pattern most strongly suggests a platelet or primary hemostasis problem rather than a coagulation factor deficiency?", options:["Petechiae, epistaxis, gum bleeding, and menorrhagia","Deep muscle hematomas and hemarthroses","Delayed bleeding after major surgery only","Pulmonary infiltrates after transfusion","Hyperviscosity symptoms"], answer:0, explain:"Primary hemostasis disorders cause mucocutaneous bleeding, petechiae, epistaxis, and menorrhagia. Factor deficiencies cause deep tissue bleeding and hemarthroses."},
    {q:"A patient with severe bleeding has low fibrinogen. Which blood product is especially rich in fibrinogen, factor VIII, factor XIII, and vWF?", options:["Cryoprecipitate","Packed RBCs","Albumin","Washed RBCs","AB plasma only"], answer:0, explain:"Cryoprecipitate is rich in fibrinogen, factor VIII, factor XIII, and vWF and is used when fibrinogen replacement is needed."},
    {q:"A patient with hemophilia A has severe joint bleeding. Which missing factor is responsible?", options:["Factor VIII","Factor IX","Factor XI","Factor VII","Factor XIII"], answer:0, explain:"Hemophilia A is factor VIII deficiency; hemophilia B is factor IX deficiency."},
    {q:"A patient has isolated prolonged PT with normal aPTT and bleeding. Which deficiency is most likely?", options:["Factor VII deficiency","Factor VIII deficiency","Factor IX deficiency","vWD type I","Factor XII deficiency"], answer:0, explain:"Isolated prolonged PT points to extrinsic pathway factor VII deficiency or warfarin effect. Isolated prolonged aPTT points to intrinsic pathway disorders such as hemophilia."}
  ],
  "heme-vte-thrombophilia": [
    {q:"A patient has unilateral leg swelling and pain. Compression ultrasound shows a noncompressible femoral vein. What is the diagnosis?", options:["Proximal DVT","Superficial thrombophlebitis only","TACO","DIC","ITP"], answer:0, explain:"Compression ultrasound is the diagnostic test of choice for DVT. A noncompressible femoral vein indicates proximal DVT, which carries substantial PE risk."},
    {q:"A patient has acute proximal DVT but also active intracranial hemorrhage, making anticoagulation temporarily contraindicated. Which intervention may be indicated?", options:["Inferior vena cava filter","Immediate high-dose warfarin despite bleeding","Aspirin alone as definitive therapy","Rituximab","Splenectomy"], answer:0, explain:"An IVC filter can be used when acute VTE exists and anticoagulation is absolutely contraindicated, such as active major bleeding. Filters do not replace anticoagulation once it becomes safe."},
    {q:"A young woman has recurrent unprovoked DVTs, miscarriages, livedo reticularis, and persistently positive lupus anticoagulant and anticardiolipin antibodies. What is the preferred long-term anticoagulant after thrombotic events?", options:["Warfarin","Aspirin alone","No treatment","Rasburicase","Desmopressin"], answer:0, explain:"Thrombotic antiphospholipid syndrome is generally treated with long-term warfarin rather than DOACs, especially in high-risk patients."},
    {q:"A patient with pancreatic cancer develops DVT 2 months after diagnosis. Which statement about cancer-associated thrombosis is most accurate?", options:["Factor Xa inhibitors are effective, but LMWH may be preferred in GI cancers, thrombocytopenia, or near surgery","Cancer-associated thrombosis never requires anticoagulation","Warfarin is always superior to all other agents","Aspirin alone is adequate treatment","IVC filter is first-line in all cases"], answer:0, explain:"Cancer-associated thrombosis is common early after diagnosis. Factor Xa inhibitors are effective, while LMWH remains useful in GI malignancy, thrombocytopenia, procedures, or bleeding concerns."},
    {q:"A 23-year-old woman develops recurrent left-sided iliofemoral DVT. Imaging shows compression of the left common iliac vein by the right common iliac artery. What is the diagnosis?", options:["May-Thurner syndrome","Felty syndrome","Richter transformation","HDFN","TACO"], answer:0, explain:"May-Thurner syndrome is compression of the left common iliac vein by the right common iliac artery, predisposing to left-sided DVT."},
    {q:"A patient with new DVT after knee replacement asks how long anticoagulation is usually required. The provoking factor was transient and major. What is the minimum typical duration?", options:["At least 3 months","3 days","Lifelong in every case","Until D-dimer normalizes after 24 hours","No anticoagulation if ultrasound is positive"], answer:0, explain:"DVT treatment is generally at least 3 months. Major transient provoking factors often allow stopping after the initial treatment period if risk-benefit supports it."},
    {q:"A patient with extensive thrombosis of both deep and superficial leg veins develops severe pain, massive edema, cyanosis, and signs of threatened limb ischemia. What is this syndrome?", options:["Phlegmasia cerulea dolens","Post-thrombotic syndrome","Ecthyma gangrenosum","TACO","TRALI"], answer:0, explain:"Phlegmasia cerulea dolens is severe venous outflow obstruction with edema, cyanosis, pain, arterial compromise, and risk of necrosis/amputation."}
  ],
  "heme-transfusion": [
    {q:"A patient develops fever, chills, flank pain, hypotension, hemoglobinuria, and a sense of impending doom minutes after starting a packed RBC transfusion. What is the most likely mechanism?", options:["ABO mismatch causing IgM-mediated intravascular hemolysis","Delayed IgG-mediated extravascular hemolysis","Citrate binding calcium","Donor anti-HLA antibodies activating lung neutrophils","Volume overload"], answer:0, explain:"Acute hemolytic transfusion reaction is usually due to ABO incompatibility, with IgM-mediated complement activation and intravascular hemolysis."},
    {q:"What is the first step when an acute hemolytic transfusion reaction is suspected?", options:["Stop the transfusion immediately and maintain IV access with normal saline","Give another unit from the same donor","Start oral iron and continue transfusion","Administer bleomycin","Perform therapeutic phlebotomy"], answer:0, explain:"The transfusion must be stopped immediately. Supportive care, clerical check, hemolysis evaluation, cultures when indicated, and renal-protective fluids/diuretics follow."},
    {q:"A transfused patient develops dyspnea, fever, hypotension, hypoxemia, and bilateral infiltrates 3 hours after transfusion. JVP is not elevated. What is the most likely diagnosis?", options:["TRALI","TACO","FNHTR","DHTR","Citrate toxicity"], answer:0, explain:"TRALI occurs within 6 hours with noncardiogenic pulmonary edema, hypoxemia, fever, and hypotension. It is not treated with diuresis."},
    {q:"An elderly patient with heart failure develops severe hypertension, JVD, cyanosis, and pulmonary edema during transfusion. Which diagnosis and treatment are most appropriate?", options:["TACO; stop transfusion, sit upright, oxygen, diuretics","TRALI; aggressive fluids and avoid diuretics","AHTR; repeat same unit slowly","PTP; aspirin only","TA-GVHD; washed RBCs"], answer:0, explain:"TACO is circulatory overload from transfusion and causes hypertension, JVD, and pulmonary edema. Treatment includes stopping transfusion, oxygen, upright positioning, and diuretics."},
    {q:"A patient with selective IgA deficiency develops bronchospasm, angioedema, urticaria, and hypotension seconds after transfusion. How should future transfusions be prepared?", options:["Use washed RBCs or products from IgA-deficient donors","Use only O-positive blood regardless of recipient","Use leukoreduced products only","Never transfuse platelets again under any circumstance","Use nonirradiated blood from close relatives"], answer:0, explain:"Anaphylactic transfusion reactions can occur in IgA-deficient patients with anti-IgA antibodies. Washed products or IgA-deficient donor products reduce plasma proteins."},
    {q:"A Hodgkin lymphoma patient requires transfusion. Which product processing reduces the risk of transfusion-associated graft-versus-host disease?", options:["Irradiation","Leukoreduction only","Washing only","Heating the blood at bedside","ABO reverse typing only"], answer:0, explain:"Irradiation inactivates donor T cells and prevents transfusion-associated GVHD. Indications include Hodgkin lymphoma, stem cell transplant, certain purine analogs, and donation from close relatives."},
    {q:"A patient develops fever and rigors 2 hours after transfusion without hypotension, dyspnea, flank pain, or hemoglobinuria. Which reaction is most likely?", options:["Febrile nonhemolytic transfusion reaction","Acute hemolytic transfusion reaction","TRALI","TACO","Anaphylactic transfusion reaction"], answer:0, explain:"FNHTR presents with fever/rigors without hemolysis or pulmonary compromise, often due to donor cytokines or leukocytes. Leukoreduction reduces risk."},
    {q:"A patient develops mild jaundice, falling hemoglobin, fever, and weakness 8 days after transfusion. Crossmatch had been negative before transfusion. What is most likely?", options:["Delayed hemolytic transfusion reaction due to anamnestic IgG response","Acute ABO hemolysis","Citrate toxicity","TACO","Post-transfusion purpura"], answer:0, explain:"Delayed hemolytic transfusion reactions occur 3-14 days later due to low-level alloantibodies not detected initially, followed by IgG-mediated extravascular hemolysis."},
    {q:"A multiparous woman develops severe thrombocytopenia, purpura, and bleeding 7 days after transfusion. What is the most likely diagnosis?", options:["Post-transfusion purpura","TACO","TRALI","AHTR","Citrate toxicity"], answer:0, explain:"Post-transfusion purpura causes severe thrombocytopenia 5-12 days after transfusion, often in previously pregnant patients. IVIG is a key treatment."},
    {q:"During massive transfusion, a trauma patient develops perioral tingling, muscle spasms, and prolonged QT. Which abnormality is most likely?", options:["Hypocalcemia from citrate binding calcium","Hypercalcemia from myeloma","Hyperuricemia from TLS","Hypokalemia from B12 therapy","Hyponatremia from SIADH"], answer:0, explain:"Citrate in blood products binds calcium during massive transfusion, causing hypocalcemia with neuromuscular symptoms and QT prolongation."},
    {q:"Which emergency blood product choice is most appropriate before crossmatch for a young woman of childbearing potential with life-threatening bleeding?", options:["O-negative packed RBCs","O-positive packed RBCs only","AB-negative plasma as RBC replacement","A-positive RBCs regardless of type","Platelets only"], answer:0, explain:"O-negative RBCs are preferred for young women of childbearing potential to avoid Rh sensitization. O-positive may be used for men and older women in emergencies."},
    {q:"Which plasma type is the universal donor plasma for emergency transfusion?", options:["AB plasma","O plasma","A plasma","B plasma","Rh-negative plasma only"], answer:0, explain:"AB plasma lacks anti-A and anti-B antibodies and is used as universal donor plasma."},
    {q:"A transfusion service performs forward typing using patient RBCs and anti-A/anti-B reagents, and reverse typing using patient serum with known A and B cells. What is the purpose?", options:["ABO blood group determination","Detection of factor VIII inhibitor","Diagnosis of DIC","Monitoring BCR-ABL response","Diagnosis of MGUS"], answer:0, explain:"Forward and reverse typing together determine ABO type and check for discrepancies."},
    {q:"A direct Coombs test is positive. What is being detected?", options:["Antibody or complement bound to the patient's RBCs in vivo","Free serum antibodies against donor RBCs only","BCR-ABL transcripts","Platelet clumping in EDTA","Uric acid crystals"], answer:0, explain:"The direct antiglobulin test detects immunoglobulin or complement already bound to patient RBCs, useful in AIHA and transfusion reactions."},
    {q:"A chronically transfused sickle cell disease patient is being prepared for transfusion. Which approach reduces alloimmunization risk?", options:["Extended antigen matching beyond ABO/RhD when feasible","Always use uncrossmatched O-positive blood","Avoid all Coombs testing","Transfuse only platelets","Use cryoprecipitate as RBC substitute"], answer:0, explain:"Patients requiring repeated transfusions, such as those with sickle cell disease, benefit from extended antigen matching to reduce alloimmunization."}
  ]
};
